  id: string;
  timestamp: Date;
  command: string;
  severity: SeverityTier;
  matchedPatterns: string[];
  context: ExecutionContext;
  userAction: 'blocked' | 'overridden' | 'cancelled';
  overrideReason?: string;
}

// Storage in SQLite for local dev, PostgreSQL for production
// Retention: 90 days default, configurable
```

